#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int lower_bound(int *arr, int n, int x) {
    int l = 0, r = n;
    while (l < r) {
        int m = l + (r - l) / 2;
        if (arr[m] < x) l = m + 1; else r = m;
    }
    return l;
}

int upper_bound(int *arr, int n, int x) {
    int l = 0, r = n;
    while (l < r) {
        int m = l + (r - l) / 2;
        if (arr[m] <= x) l = m + 1; else r = m;
    }
    return l;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int S, R; scanf("%d %d", &S, &R);
        int *samples = (int*)malloc(S * sizeof(int));
        for (int i = 0; i < S; ++i) scanf("%d", &samples[i]);
        qsort(samples, S, sizeof(int), cmp_int);
        for (int i = 0; i < R; ++i) {
            int L, H; scanf("%d %d", &L, &H);
            int left = lower_bound(samples, S, L);
            int right = upper_bound(samples, S, H);
            printf("%d\n", right - left);
        }
        free(samples);
    }
    return 0;
}

