const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = data[idx++];
let output = [];
for (let t = 0; t < T; ++t) {
  const S = data[idx++];
  const R = data[idx++];
  const samples = data.slice(idx, idx + S);
  idx += S;
  samples.sort((a, b) => a - b);
  for (let i = 0; i < R; ++i) {
    const L = data[idx++];
    const H = data[idx++];
    // lower bound
    let lo = 0, hi = samples.length;
    while (lo < hi) {
      const mid = (lo + hi) >> 1;
      if (samples[mid] < L) lo = mid + 1; else hi = mid;
    }
    const left = lo;
    // upper bound
    lo = 0; hi = samples.length;
    while (lo < hi) {
      const mid = (lo + hi) >> 1;
      if (samples[mid] <= H) lo = mid + 1; else hi = mid;
    }
    const right = lo;
    output.push(String(right - left));
  }
}
console.log(output.join('\n'));
